module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    reg [15:0] a_reg, b_reg;
    reg [15:0] quotient, remainer;
    integer i;

    always @(A, B) begin
        a_reg = A;
        b_reg = B;
    end

    always @(a_reg, b_reg) begin
        quotient = 0;
        remainer = 0;
        for (i = 15; i >= 0; i = i - 1) begin
            remainer = {remainer[14:0], a_reg[i]};
            if (remainer >= b_reg) begin
                remainer = remainer - b_reg;
                quotient[i] = 1'b1;
            end
        end
        result = quotient;
        odd = remainer;
    end

endmodule
